/**
 * MalwareScope — Main App
 * Layout, state management. All polling via useAnalysis hook.
 * Components are purely presentational — they receive props only.
 */

import { useState, useRef } from "react";
import { useAnalysis } from "./hooks/useAnalysis";
import PipelineFlow from "./components/PipelineFlow";
import AgentStatus from "./components/AgentStatus";
import Timeline from "./components/Timeline";
import IOCTable from "./components/IOCTable";
import ReportPanel from "./components/ReportPanel";
import ResponsePanel from "./components/ResponsePanel";
import { exportReport } from "./api/client";

const TABS = ["Agents", "Timeline", "IOCs", "Response"];

function DropZone({ onFile, disabled }) {
  const inputRef = useRef(null);
  const [dragging, setDragging] = useState(false);

  const handleFile = (file) => {
    if (file && !disabled) onFile(file);
  };

  return (
    <div
      className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all duration-200
        ${dragging ? "border-blue-500 bg-blue-950/30" : "border-gray-700 bg-gray-900/40 hover:border-gray-500"}
        ${disabled ? "opacity-50 cursor-not-allowed" : ""}`}
      onClick={() => !disabled && inputRef.current?.click()}
      onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
      onDragLeave={() => setDragging(false)}
      onDrop={(e) => {
        e.preventDefault();
        setDragging(false);
        handleFile(e.dataTransfer.files[0]);
      }}
    >
      <input
        ref={inputRef}
        type="file"
        className="hidden"
        onChange={(e) => handleFile(e.target.files[0])}
        disabled={disabled}
      />
      <div className="text-4xl mb-3">🛡️</div>
      <p className="text-gray-300 font-semibold mb-1">Drop malware sample here</p>
      <p className="text-gray-600 text-sm">or click to browse — any file type accepted</p>
    </div>
  );
}

function StatusBadge({ status }) {
  const styles = {
    queued:   "bg-gray-800 text-gray-400",
    running:  "bg-blue-900 text-blue-300 animate-pulse",
    complete: "bg-emerald-900 text-emerald-300",
    error:    "bg-red-900 text-red-300",
    not_found:"bg-gray-800 text-gray-500",
  };
  return (
    <span className={`text-xs font-mono px-2 py-0.5 rounded font-bold uppercase ${styles[status] || styles.queued}`}>
      {status}
    </span>
  );
}

async function handleExport(jobId) {
  try {
    const report = await exportReport(jobId);
    const blob = new Blob([JSON.stringify(report, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `malwarescope-report-${jobId.slice(0, 8)}.json`;
    a.click();
    URL.revokeObjectURL(url);
  } catch (err) {
    console.error("Export failed:", err);
  }
}

export default function App() {
  const { analyze, reset, jobId, job, uploading, error } = useAnalysis();
  const [activeTab, setActiveTab] = useState("Agents");

  const progress = job?.progress || null;
  const report = job?.progress?.report?.findings || null;
  const iocs = report?.iocs || job?.progress?.static?.findings?.iocs || null;
  const events = job?.events || [];
  const response = job?.response || null;
  const isDone = job?.status === "complete";
  const isError = job?.status === "error";

  return (
    <div className="min-h-screen bg-gray-950 text-gray-100 font-sans">
      {/* Header */}
      <header className="border-b border-gray-800 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <span className="text-2xl">⚡</span>
          <div>
            <h1 className="text-xl font-bold tracking-tight text-white">MalwareScope</h1>
            <p className="text-xs text-gray-500 font-mono">
              Autonomous Critical Infrastructure Threat Detection · Powered by Claude + Google ADK
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {job && <StatusBadge status={job.status} />}
          {isDone && jobId && (
            <button
              onClick={() => handleExport(jobId)}
              className="text-xs text-emerald-500 hover:text-emerald-300 font-mono border border-emerald-800 px-3 py-1 rounded hover:border-emerald-600 transition-colors"
            >
              Export JSON
            </button>
          )}
          {job && (
            <button
              onClick={reset}
              className="text-xs text-gray-500 hover:text-gray-300 font-mono border border-gray-700 px-3 py-1 rounded hover:border-gray-500 transition-colors"
            >
              New Analysis
            </button>
          )}
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 py-6">
        {/* Upload area — hide when job is running/complete */}
        {!job && (
          <div className="max-w-2xl mx-auto">
            <div className="mb-6 text-center">
              <h2 className="text-2xl font-bold text-white mb-2">Analyze a Malware Sample</h2>
              <p className="text-gray-500 text-sm">
                Upload any suspected malware file. The ADK multi-agent pipeline will perform
                static analysis, behavioral simulation, forensic analysis, and generate a
                threat report — all autonomously.
              </p>
            </div>
            <DropZone onFile={analyze} disabled={uploading} />
            {uploading && (
              <p className="text-center text-blue-400 text-sm font-mono mt-4 animate-pulse">
                Uploading and starting analysis…
              </p>
            )}
            {error && (
              <div className="mt-4 bg-red-950 border border-red-800 rounded-xl p-4">
                <p className="text-red-300 text-sm font-mono">Error: {error}</p>
              </div>
            )}
          </div>
        )}

        {/* Analysis in progress or complete */}
        {job && (
          <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
            {/* Left panel — pipeline + tabs */}
            <div className="xl:col-span-2 space-y-4">
              {/* Pipeline flow — always visible */}
              <PipelineFlow progress={progress} />

              {/* Error banner */}
              {isError && (
                <div className="bg-red-950 border border-red-800 rounded-xl p-4">
                  <p className="text-red-300 text-sm font-mono">
                    Pipeline error: {job.error || "Unknown error"}
                  </p>
                </div>
              )}

              {/* Tab bar */}
              <div className="flex gap-1 border-b border-gray-800 pb-0">
                {TABS.map((tab) => {
                  const hasResponseActivity = tab === "Response" && response && response.status !== "idle";
                  return (
                    <button
                      key={tab}
                      onClick={() => setActiveTab(tab)}
                      className={`px-4 py-2 text-sm font-mono rounded-t-lg border-b-2 transition-colors relative
                        ${activeTab === tab
                          ? "border-blue-500 text-blue-400 bg-blue-950/20"
                          : "border-transparent text-gray-500 hover:text-gray-300"}`}
                    >
                      {tab}
                      {hasResponseActivity && activeTab !== "Response" && (
                        <span className="absolute top-1.5 right-1 w-1.5 h-1.5 rounded-full bg-blue-400" />
                      )}
                    </button>
                  );
                })}
              </div>

              {/* Tab content */}
              <div>
                {activeTab === "Agents"   && <AgentStatus progress={progress} />}
                {activeTab === "Timeline" && <Timeline events={events} />}
                {activeTab === "IOCs"     && <IOCTable iocs={iocs} />}
                {activeTab === "Response" && <ResponsePanel response={response} />}
              </div>
            </div>

            {/* Right panel — report */}
            <div className="xl:col-span-1">
              <ReportPanel report={report} />
            </div>
          </div>
        )}
      </main>
    </div>
  );
}
